import { boolean, integer, jsonb, numeric, pgTable, text, timestamp, uuid, varchar } from "drizzle-orm/pg-core";
export const customerGroupsTable = pgTable("customer_groups", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    groupCode: varchar("group_code", { length: 50 }).notNull(),
    groupName: varchar("group_name", { length: 120 }).notNull(),
    description: text("description"),
    isActive: boolean("is_active").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const customersTable = pgTable("customers", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerCode: varchar("customer_code", { length: 50 }).notNull(),
    customerName: varchar("customer_name", { length: 160 }).notNull(),
    customerType: varchar("customer_type", { length: 40 }).notNull(),
    companyName: varchar("company_name", { length: 160 }),
    email: varchar("email", { length: 160 }).notNull(),
    phone: varchar("phone", { length: 40 }),
    taxNumber: varchar("tax_number", { length: 80 }),
    customerGroupId: uuid("customer_group_id"),
    paymentTermsId: uuid("payment_terms_id"),
    preferredCurrencyCode: varchar("preferred_currency_code", { length: 3 }).notNull(),
    status: varchar("status", { length: 40 }).notNull(),
    portalEnabled: boolean("portal_enabled").notNull(),
    portalUserId: uuid("portal_user_id"),
    metadata: jsonb("metadata").notNull(),
    createdBy: uuid("created_by"),
    updatedBy: uuid("updated_by"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
    deletedAt: timestamp("deleted_at"),
    version: integer("version").notNull(),
});
export const customerAddressesTable = pgTable("customer_addresses", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerId: uuid("customer_id").notNull(),
    addressType: varchar("address_type", { length: 40 }).notNull(),
    contactName: varchar("contact_name", { length: 120 }),
    contactPhone: varchar("contact_phone", { length: 40 }),
    line1: varchar("line1", { length: 180 }).notNull(),
    line2: varchar("line2", { length: 180 }),
    city: varchar("city", { length: 100 }).notNull(),
    state: varchar("state", { length: 100 }),
    postalCode: varchar("postal_code", { length: 30 }).notNull(),
    country: varchar("country", { length: 2 }).notNull(),
    isDefaultBilling: boolean("is_default_billing").notNull(),
    isDefaultShipping: boolean("is_default_shipping").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
    deletedAt: timestamp("deleted_at"),
});
export const customerNotesTable = pgTable("customer_notes", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerId: uuid("customer_id").notNull(),
    note: text("note").notNull(),
    visibility: varchar("visibility", { length: 40 }).notNull(),
    createdBy: uuid("created_by"),
    createdAt: timestamp("created_at").notNull(),
});
export const customerCreditLimitsTable = pgTable("customer_credit_limits", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerId: uuid("customer_id").notNull(),
    creditLimit: numeric("credit_limit").notNull(),
    creditUsed: numeric("credit_used").notNull(),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    effectiveFrom: timestamp("effective_from").notNull(),
    effectiveTo: timestamp("effective_to"),
    updatedBy: uuid("updated_by"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const customerPricingRulesTable = pgTable("customer_pricing_rules", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerId: uuid("customer_id").notNull(),
    ruleType: varchar("rule_type", { length: 40 }).notNull(),
    productId: uuid("product_id"),
    productCategoryId: uuid("product_category_id"),
    minimumQuantity: numeric("minimum_quantity").notNull(),
    discountPercent: numeric("discount_percent"),
    fixedPrice: numeric("fixed_price"),
    currencyCode: varchar("currency_code", { length: 3 }).notNull(),
    effectiveFrom: timestamp("effective_from").notNull(),
    effectiveTo: timestamp("effective_to"),
    isActive: boolean("is_active").notNull(),
    createdBy: uuid("created_by"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const customerTaxExemptionsTable = pgTable("customer_tax_exemptions", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerId: uuid("customer_id").notNull(),
    certificateNumber: varchar("certificate_number", { length: 120 }).notNull(),
    exemptionType: varchar("exemption_type", { length: 80 }).notNull(),
    issuingRegion: varchar("issuing_region", { length: 80 }).notNull(),
    expiresAt: timestamp("expires_at").notNull(),
    documentUrl: text("document_url"),
    isActive: boolean("is_active").notNull(),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
export const customerShippingPreferencesTable = pgTable("customer_shipping_preferences", {
    id: uuid("id").primaryKey(),
    companyId: uuid("company_id").notNull(),
    customerId: uuid("customer_id").notNull(),
    preferredCarrier: varchar("preferred_carrier", { length: 120 }),
    serviceLevel: varchar("service_level", { length: 120 }),
    deliveryInstructions: text("delivery_instructions"),
    allowPartialShipments: boolean("allow_partial_shipments").notNull(),
    preferredWarehouseId: uuid("preferred_warehouse_id"),
    createdAt: timestamp("created_at").notNull(),
    updatedAt: timestamp("updated_at").notNull(),
});
